      "the_equivalence_point_is_the_stoichiom": "Điểm tương đương là điểm cân bằng hóa học lượng. pH tại điểm tương đương phụ thuộc vào độ mạnh axit/bazơ — chỉ là pH 7 với axit mạnh + bazơ mạnh.",
      "the_exothermic_reaction_can_cause_viol": "Phản ứng tỏa nhiệt có thể gây sôi dữ dội và văng bắn",
      "when_water_hits_concentrated_acid_the_": "Khi nước chạm axit đặc, nhiệt giải phóng có thể làm nước sôi ngay lập tức, gây văng bắn axit nóng dữ dội. Thêm axit vào nước phân tán nhiệt qua thể tích nước lớn hơn.",
      "above_7": "Trên 7",
      "at_equivalence_only_the_conjugate_base": "Tại điểm tương đương, chỉ còn lại bazơ liên hợp (A⁻). Bazơ liên hợp của axit yếu tự chúng là bazơ yếu, làm dung dịch có tính bazơ (pH > 7).",
      "strong_acid_strong_base_or_weak_acid_s": "Axit mạnh + Bazơ mạnh hoặc Axit yếu + Bazơ mạnh",
      "phenolphthalein_transitions_at_ph_8_2_": "Phenolphtalein chuyển màu ở pH 8,2-10,0, tương ứng với pH tương đương bazơ của chuẩn độ axit yếu + bazơ mạnh. Nó cũng hiệu quả cho AM+BM vì bước nhảy sắc nét cắt qua khoảng của nó.",
      "ammonia_or_acids": "Amoniac hoặc axit",
      "bleach_ammonia_chloramine_gas_toxic_bl": "Thuốc tẩy + amoniac = khí cloramin (độc). Thuốc tẩy + axit = khí clo (độc). Cả hai đều có thể gây tổn thương hô hấp nghiêm trọng hoặc tử vong. KHÔNG BAO GIỜ kết hợp thuốc tẩy với bất kỳ hóa chất nào.",
      "23_45_has_4_significant_figures_the_la": "23,45 có 4 chữ số có nghĩa. Chữ số cuối (5) được ước lượng giữa các vạch chia. Buret chính xác đến ±0,05 mL.",
      "ph_pka": "pH = pKa",
      "at_half_equivalence_ha_a_so_henderson_": "Tại điểm nửa tương đương, [HA] = [A⁻], nên Henderson–Hasselbalch cho pH = pKa + log(1) = pKa. Đây là trung tâm của vùng đệm.",
      "when_handling_1m_concentrated_acids_or": "Khi xử lý axit hoặc bazơ đặc >1M",
      "face_shields_provide_splash_protection": "Tấm che mặt cung cấp bảo vệ chống văng bắn cho toàn bộ khuôn mặt. Bắt buộc cho chất ăn mòn đặc (>1M), thao tác gia nhiệt, và bất kỳ quy trình nào có nguy cơ văng bắn ngoài vùng mắt.",
      "suit_up": "Trang bị",
      "lab_scan": "Quét phòng thí nghiệm",
      "chemicals": "Hóa chất",
      "safety_drill": "Diễn tập an toàn",
      "naoh_causes_alkali_burns_that_penetrat": "NaOH gây bỏng kiềm thấm vào mắt trong 10 giây. Không có kính bảo hộ, một lần văng bắn có thể gây mất thị lực vĩnh viễn.",
      "concentrated_hcl_dissolves_skin_on_con": "HCl đặc hòa tan da khi tiếp xúc. Ngay cả axit loãng cũng gây kích ứng. Tay bạn ở gần hóa chất nhất.",
      "a_splash_of_acid_or_base_will_burn_thr": "Một lần văng axit hoặc bazơ sẽ cháy xuyên qua quần áo và da. Áo choàng cung cấp một lớp rào cản có thể tháo rời.",
      "a_dropped_beaker_sends_glass_and_chemi": "Một cốc rơi làm văng thủy tinh và hóa chất khắp sàn. Giày hở mũi nghĩa là axit trên chân trần.",
