      "nervous": "Thần kinh",
      "cns_brain_spinal_cord_and_pns_31_spina": "Hệ thần kinh trung ương (não + tủy sống) và hệ thần kinh ngoại biên (31 đôi dây thần kinh tủy, 12 đôi dây thần kinh sọ, hệ thần kinh tự chủ).",
      "brain": "Não",
      "lightest_sleep_transition_from_wakeful": "Giấc ngủ nhẹ nhất — chuyển tiếp từ thức. Cử động mắt chậm, lăn tròn, trương lực cơ giảm. Giật mình khi ngủ (co giật cơ) rất thường gặp. Dễ đánh thức. Sóng nhọn đỉnh xuất hiện trên EEG.",
      "true_sleep_begins_core_body_temperatur": "Giấc ngủ thực sự bắt đầu. Nhiệt độ lõi cơ thể giảm, nhịp tim chậm lại. Thoi ngủ (phóng điện đồi thị-vỏ não) bảo vệ giấc ngủ và củng cố trí nhớ vận động. Phức hợp K là các sóng lớn phản ứng với kích thích bên ngoài.",
      "deep_slow_wave_sleep_sws_most_restorat": "Giấc ngủ sâu/sóng chậm (SWS). Giai đoạn phục hồi nhất. Bài tiết hormone tăng trưởng đạt đỉnh. Hệ glymphatic dọn sạch chất thải của não (amyloid-β). Củng cố trí nhớ khai báo diễn ra ở đây. Khó đánh thức nhất; có tình trạng say ngủ khi thức dậy.",
      "dreaming_stage_brain_is_highly_active_": "Giai đoạn mơ. Não hoạt động cao độ (giống lúc thức), nhưng cơ thể bị liệt (mất trương lực do thân não ức chế các nơ-ron vận động). Cử động mắt nhanh liên hợp. Xử lý trí nhớ cảm xúc và giải quyết vấn đề sáng tạo. Các chu kỳ dài ra suốt đêm.",
      "cerebral_cortex_4_lobes": "Vỏ não (4 thùy)",
      "brodmann_areas_map_52_cytoarchitectura": "Các vùng Brodmann lập bản đồ 52 vùng cấu trúc tế bào. Vỏ vận động sơ cấp (vùng 4), vỏ cảm giác thân thể sơ cấp (vùng 3,1,2), vỏ thị giác sơ cấp (vùng 17), vỏ thính giác sơ cấp (vùng 41,42). Vỏ trước trán myelin hóa cuối cùng (~25 tuổi).",
      "cerebellum": "Tiểu não",
      "purkinje_cells_are_among_the_largest_n": "Tế bào Purkinje là một trong những nơ-ron lớn nhất; mỗi tế bào nhận khoảng 200.000 đầu vào synap. Vỏ tiểu não có 3 lớp: lớp phân tử, lớp Purkinje và lớp hạt. Nghiên cứu mới cho thấy vai trò trong nhận thức, cảm xúc và ngôn ngữ.",
      "brainstem_midbrain_pons_medulla": "Thân não (não giữa, cầu não, hành não)",
      "contains_nuclei_for_cranial_nerves_iii": "Chứa nhân của các dây thần kinh sọ III–XII. Hệ lưới hoạt hóa (RAS) là “công tắc bật” của não — tổn thương gây hôn mê. Bắt chéo tháp ở hành não: bắt chéo vận động giải thích sự điều khiển vận động đối bên.",
      "hippocampus": "Hồi hải mã",
      "memory_replay_during_sleep_hippocampal": "Tái hiện trí nhớ khi ngủ: các nơ-ron hồi hải mã “phát lại” trải nghiệm ban ngày trong giấc ngủ N3, chuyển ký ức đến tân vỏ não. Tế bào lưới ở vỏ nội khứu cung cấp tọa độ không gian cho các tế bào vị trí của hồi hải mã.",
      "amygdala": "Hạch hạnh nhân",
      "fear_conditioning_pathway_auditory_cor": "Đường dẫn điều kiện hóa sợ hãi: vỏ thính giác → hạch hạnh nhân bên → hạch hạnh nhân trung tâm → vùng dưới đồi (phản ứng căng thẳng) + PAG (đông cứng). Tương tác hạch hạnh nhân-trước trán cho phép điều hòa cảm xúc — nền tảng của liệu pháp nhận thức hành vi (CBT).",
      "thalamus": "Đồi thị",
      "key_nuclei_vpl_vpm_somatosensory_relay": "Các nhân chính: VPL/VPM (chuyển tiếp cảm giác thân thể), LGN (chuyển tiếp thị giác đến V1), MGN (chuyển tiếp thính giác đến A1), gối đồi thị (chú ý), nhân trước (trí nhớ, vòng Papez).",
      "hypothalamus": "Vùng dưới đồi",
      "thermostat_analogy_anterior_hypothalam": "Ví von bộ điều nhiệt: vùng dưới đồi trước kích hoạt làm mát (giãn mạch, đổ mồ hôi); vùng dưới đồi sau kích hoạt làm ấm (run, co mạch). Sốt = điểm đặt tăng do prostaglandin khi nhiễm trùng.",
      "corpus_callosum": "Thể chai",
      "split_brain_experiments_revealed_hemis": "Các thí nghiệm não tách đôi tiết lộ sự chuyên biệt hóa bán cầu: bán cầu trái = ngôn ngữ, logic; bán cầu phải = xử lý không gian, tổng thể. Thông tin trình bày cho một trường thị giác được xử lý bởi bán cầu đối bên.",
      "basal_ganglia": "Hạch nền",
      "dopamine_from_substantia_nigra_modulat": "Dopamine từ chất đen điều chỉnh đường trực tiếp (D1, kích thích) và đường gián tiếp (D2, ức chế). Mất sự điều chỉnh này trong bệnh Parkinson gây khó khăn đặc trưng khi khởi động vận động.",
      "spinal_cord": "Tủy sống",
