      "barry_harris_1929_2021_codified_bebop_": "Barry Harris (1929-2021) đã hệ thống hóa hòa âm bebop. Hệ thống của ông dùng hợp âm bậc sáu thay cho hợp âm bậc bảy và thêm các hợp âm giảm đi ngang giữa các bậc âm giai để dẫn giọng mượt mà.",
      "ii_v_i_jazz": "ii-V-I (Jazz)",
      "12_bar_blues": "Blues 12 Ô Nhịp",
      "vi_iv_i_v_emo_alt": "vi-IV-I-V (Emo/Alt)",
      "1st_overtone": "Bồi âm 1",
      "2nd_overtone": "Bồi âm 2",
