      "arpeggiator_gate": "Gate arpeggiator",
      "an_arpeggiator_plays_the_notes_of_a_ch": "🔬 Arpeggiator chơi các nốt của một hợp âm lần lượt theo trình tự. «Lên» đi từ thấp đến cao, tạo năng lượng đi lên. «Xuống» đi xuống, cho cảm giác thác đổ. Tốc độ điều khiển độ nhanh (càng nhỏ càng nhanh). Gate điều khiển mỗi nốt ngân bao lâu (100% = legato, 10% = staccato). Thử tốc độ=100 ms + 4 quãng tám + mẫu đi lên để có một arpeggio trance cổ điển!",
      "live_mic_effects_lab": "🎤 Phòng thí nghiệm hiệu ứng micro trực tiếp",
      "sing_speak_or_play_an_instrument_hear_": "Hát, nói hoặc chơi một nhạc cụ — nghe hiệu ứng theo thời gian thực!",
      "monitor_hear_yourself_use_headphones": "🔊 Nghe kiểm tra (nghe chính bạn — dùng tai nghe!)",
      "microphone_monitor_volume": "Âm lượng nghe kiểm tra micro",
      "how_effects_change_sound_waves": "🔬 Hiệu ứng thay đổi sóng âm như thế nào",
      "filter_cutoff": "Bộ lọc (Điểm cắt)",
      "removes_frequencies_above_lowpass_or_b": "Loại bỏ các tần số phía trên (thông thấp) hoặc phía dưới (thông cao) một ngưỡng. Giống như khum tay trước miệng — các tần số cao biến mất, âm thanh trở nên «tối» hơn.",
      "delay": "Delay",
      "creates_echoes_by_copying_the_signal_a": "Tạo tiếng vang bằng cách sao chép tín hiệu và phát lại sau một khoảng ngắn. Hồi tiếp điều khiển số lần tiếng vang lặp lại.",
      "reverb_2": "Reverb",
      "simulates_room_acoustics_by_creating_t": "Mô phỏng âm học của một căn phòng bằng cách tạo hàng nghìn tiếng vang tí hon hòa lẫn vào nhau. Phòng nhỏ = reverb ngắn, thánh đường = reverb dài.",
      "distortion": "Distortion",
      "clips_the_waveform_peaks_turning_smoot": "Cắt các đỉnh của dạng sóng, biến sóng sin mượt mà thành hình gồ ghề, góc cạnh. Điều này thêm các bồi âm mới không có trong âm gốc.",
      "chorus": "Chorus",
      "duplicates_the_signal_with_a_slight_co": "Nhân đôi tín hiệu với một độ trễ nhỏ thay đổi liên tục. Điều này mô phỏng nhiều giọng/nhạc cụ chơi cùng nhau lệch nhịp một chút.",
      "tremolo": "Tremolo",
      "rapidly_varies_the_volume_up_and_down_": "Thay đổi âm lượng lên xuống nhanh, tạo hiệu ứng nhấp nháy. Thường gặp trong guitar surf và nhạc organ.",
      "use_headphones_when_monitoring_to_avoi": "Dùng tai nghe khi nghe kiểm tra để tránh vòng hồi tiếng! Micro đi qua tất cả các hiệu ứng ở trên (bộ lọc, delay, reverb, v.v.) — chỉnh chúng để nghe từng cái biến đổi giọng hoặc nhạc cụ của bạn ra sao.",
      "connect_your_microphone_to_run_your_vo": "Kết nối micro để đưa giọng hoặc nhạc cụ của bạn qua chuỗi hiệu ứng theo thời gian thực.",
      "see_your_voice_as_a_waveform_frequency": "Thấy giọng của bạn dưới dạng sóng + phổ tần số. Nghe cách bộ lọc, delay, reverb, distortion và chorus thay đổi sóng âm về mặt vật lý.",
      "xy_performance_pad": "🎯 Pad Trình Diễn XY",
      "touch_drag_x_pitch_y_filter_effect": "Chạm và kéo — X = cao độ, Y = bộ lọc/hiệu ứng",
      "xy_pad_performance": "Trình diễn Pad XY",
      "the_xy_pad_maps_your_finger_mouse_posi": "Pad XY ánh xạ vị trí ngón tay/chuột của bạn tới các thông số âm nhạc theo thời gian thực. Trục X điều khiển cao độ (trái = thấp, phải = cao). Trục Y điều khiển tần số cắt của bộ lọc (trên = sáng, dưới = tối). Điều này giống các nhạc cụ như Korg Kaoss Pad, thứ đã cách mạng hóa trình diễn nhạc điện tử trực tiếp bằng cách biến cử chỉ 2D thành âm thanh.",
      "xy_performance_pad_left_right_is_pitch": "Pad trình diễn XY. Trái–phải là cao độ, trên–dưới là độ sáng bộ lọc. Dùng phím mũi tên để di chuyển và chơi một nốt; nhấn Esc hoặc Space để dừng.",
